import{_ as a,o as r,c as l,ae as o}from"./chunks/framework.BeVX27ge.js";const p=JSON.parse('{"title":"常見問題 FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/faq.md","filePath":"zh-TW/faq.md"}'),i={name:"zh-TW/faq.md"};function e(d,t,h,n,s,q){return r(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="常見問題-faq" tabindex="-1">常見問題 FAQ <a class="header-anchor" href="#常見問題-faq" aria-label="Permalink to &quot;常見問題 FAQ&quot;">​</a></h1><blockquote><p>遇到問題？在這裡找答案</p></blockquote><h2 id="目錄" tabindex="-1">目錄 <a class="header-anchor" href="#目錄" aria-label="Permalink to &quot;目錄&quot;">​</a></h2><ul><li><a href="#登入與帳號">登入與帳號</a></li><li><a href="#對話練習">對話練習</a></li><li><a href="#評量報告">評量報告</a></li><li><a href="#練習歷史">練習歷史</a></li><li><a href="#知識助手">知識助手</a></li><li><a href="#管理員功能">管理員功能</a></li><li><a href="#系統與效能">系統與效能</a></li><li><a href="#錯誤訊息速查">錯誤訊息速查</a></li></ul><hr><h2 id="登入與帳號" tabindex="-1">登入與帳號 <a class="header-anchor" href="#登入與帳號" aria-label="Permalink to &quot;登入與帳號&quot;">​</a></h2><h3 id="q-我無法登入系統" tabindex="-1">Q: 我無法登入系統？ <a class="header-anchor" href="#q-我無法登入系統" aria-label="Permalink to &quot;Q: 我無法登入系統？&quot;">​</a></h3><p><strong>A:</strong> 請依序檢查以下項目：</p><ol><li>確認使用的是公司帳號（Google 或 Microsoft），而非個人帳號</li><li>確認帳號已由管理員新增至系統中</li><li>確認帳號狀態為「可用」（非「停用」）</li><li>嘗試清除瀏覽器快取後重新登入</li><li>如問題持續，聯繫公司管理員</li></ol><h3 id="q-登入後顯示「帳號已停用」" tabindex="-1">Q: 登入後顯示「帳號已停用」？ <a class="header-anchor" href="#q-登入後顯示「帳號已停用」" aria-label="Permalink to &quot;Q: 登入後顯示「帳號已停用」？&quot;">​</a></h3><p><strong>A:</strong> 您的帳號已被管理員設為停用狀態。請聯繫管理員將帳號狀態改回「可用」。</p><h3 id="q-登入後看不到某些功能-如管理設定、知識助手" tabindex="-1">Q: 登入後看不到某些功能（如管理設定、知識助手）？ <a class="header-anchor" href="#q-登入後看不到某些功能-如管理設定、知識助手" aria-label="Permalink to &quot;Q: 登入後看不到某些功能（如管理設定、知識助手）？&quot;">​</a></h3><p><strong>A:</strong> 功能的可見性取決於您的角色權限設定。不同角色可存取的功能不同：</p><table tabindex="0"><thead><tr><th>角色</th><th>可使用的功能</th></tr></thead><tbody><tr><td>使用者</td><td>對話練習、評量報告、練習歷史、儀表板</td></tr><tr><td>管理員</td><td>上述功能 + 使用者管理、Prompt 管理、階段管理、知識庫管理</td></tr></tbody></table><p>如需額外權限，請聯繫管理員調整角色設定。</p><h3 id="q-如何登出系統" tabindex="-1">Q: 如何登出系統？ <a class="header-anchor" href="#q-如何登出系統" aria-label="Permalink to &quot;Q: 如何登出系統？&quot;">​</a></h3><p><strong>A:</strong> 點擊頁面右上方的登出圖示（箭頭向右），確認「您確定要登出嗎？」後即可登出。</p><h3 id="q-如何切換語言" tabindex="-1">Q: 如何切換語言？ <a class="header-anchor" href="#q-如何切換語言" aria-label="Permalink to &quot;Q: 如何切換語言？&quot;">​</a></h3><p><strong>A:</strong> 點擊頁面右上方的語言切換器，選擇您偏好的語言（繁體中文 / 越南文）。切換後介面會立即更新。</p><hr><h2 id="對話練習" tabindex="-1">對話練習 <a class="header-anchor" href="#對話練習" aria-label="Permalink to &quot;對話練習&quot;">​</a></h2><h3 id="q-「隨機角色」和「自訂角色」有什麼差別" tabindex="-1">Q: 「隨機角色」和「自訂角色」有什麼差別？ <a class="header-anchor" href="#q-「隨機角色」和「自訂角色」有什麼差別" aria-label="Permalink to &quot;Q: 「隨機角色」和「自訂角色」有什麼差別？&quot;">​</a></h3><p><strong>A:</strong></p><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td>隨機角色</td><td>系統完全隨機生成客戶角色（年齡、職業、性別、收入等全部隨機），適合快速開始練習</td></tr><tr><td>自訂角色</td><td>您可以指定部分或全部客戶屬性（例如設定「高收入已婚」），未指定的部分由系統隨機補充</td></tr></tbody></table><h3 id="q-自訂角色時-一定要填寫所有欄位嗎" tabindex="-1">Q: 自訂角色時，一定要填寫所有欄位嗎？ <a class="header-anchor" href="#q-自訂角色時-一定要填寫所有欄位嗎" aria-label="Permalink to &quot;Q: 自訂角色時，一定要填寫所有欄位嗎？&quot;">​</a></h3><p><strong>A:</strong> 不需要。所有欄位都是選填的。您可以只設定您關心的屬性，其餘由 AI 自動補充。例如只設定「年齡 35、已婚、高收入」，系統會自動生成其他屬性。</p><h3 id="q-mbti-人格類型會影響-ai-客戶的行為嗎" tabindex="-1">Q: MBTI 人格類型會影響 AI 客戶的行為嗎？ <a class="header-anchor" href="#q-mbti-人格類型會影響-ai-客戶的行為嗎" aria-label="Permalink to &quot;Q: MBTI 人格類型會影響 AI 客戶的行為嗎？&quot;">​</a></h3><p><strong>A:</strong> 是的。MBTI 類型會顯著影響 AI 客戶的溝通風格、決策方式和反應模式。例如：</p><ul><li><strong>ISTJ</strong>（物流師）型客戶會更重視數據和細節</li><li><strong>ENFP</strong>（競選者）型客戶會更注重情感連結</li><li><strong>INTJ</strong>（建築師）型客戶會直接切入重點</li></ul><p>您可以在角色設定面板中點擊「個性」欄位旁的提示圖示查看各類型的詳細說明。</p><h3 id="q-角色生成需要等很久" tabindex="-1">Q: 角色生成需要等很久？ <a class="header-anchor" href="#q-角色生成需要等很久" aria-label="Permalink to &quot;Q: 角色生成需要等很久？&quot;">​</a></h3><p><strong>A:</strong> 角色生成通常需要數秒時間。如果等待超過 30 秒，可能是網路問題，請嘗試重新整理頁面後再試。</p><h3 id="q-對話中-ai-客戶的回應不太合理" tabindex="-1">Q: 對話中 AI 客戶的回應不太合理？ <a class="header-anchor" href="#q-對話中-ai-客戶的回應不太合理" aria-label="Permalink to &quot;Q: 對話中 AI 客戶的回應不太合理？&quot;">​</a></h3><p><strong>A:</strong> 可能的原因和建議：</p><ol><li><strong>角色設定過於極端</strong> — 嘗試使用更合理的屬性組合</li><li><strong>對話脈絡不清楚</strong> — 嘗試用更明確的表達方式溝通</li><li><strong>Prompt 需要調整</strong> — 向管理員回報，請管理員檢視並調整 AI 的 Prompt 設定</li></ol><h3 id="q-訊息無法傳送-顯示安全提示" tabindex="-1">Q: 訊息無法傳送，顯示安全提示？ <a class="header-anchor" href="#q-訊息無法傳送-顯示安全提示" aria-label="Permalink to &quot;Q: 訊息無法傳送，顯示安全提示？&quot;">​</a></h3><p><strong>A:</strong> 系統內建內容安全檢測機制。當訊息中包含以下內容時會被攔截：</p><ul><li>個人資料（電話、地址、身分證號等）</li><li>嘗試繞過系統安全限制的內容</li><li>不當或高風險內容</li><li>惡意連結</li></ul><p>請修改訊息內容後重新傳送。這些檢測是為了確保練習環境的安全性。</p><h3 id="q-練習中途離開-之後還能繼續嗎" tabindex="-1">Q: 練習中途離開，之後還能繼續嗎？ <a class="header-anchor" href="#q-練習中途離開-之後還能繼續嗎" aria-label="Permalink to &quot;Q: 練習中途離開，之後還能繼續嗎？&quot;">​</a></h3><p><strong>A:</strong> 可以。未結束的練習可透過以下方式繼續：</p><ul><li>儀表板近期紀錄的「繼續練習」按鈕</li><li>練習歷史的「繼續練習」按鈕</li></ul><p>繼續練習時，AI 客戶對之前的對話會有模糊的印象。</p><h3 id="q-可以跟同一位客戶重新練習嗎" tabindex="-1">Q: 可以跟同一位客戶重新練習嗎？ <a class="header-anchor" href="#q-可以跟同一位客戶重新練習嗎" aria-label="Permalink to &quot;Q: 可以跟同一位客戶重新練習嗎？&quot;">​</a></h3><p><strong>A:</strong> 可以。在儀表板或練習歷史中點擊「重新挑戰」，即可使用相同的客戶角色設定開始全新的對話。這對於比較不同策略的效果非常有幫助。</p><h3 id="q-什麼時候應該結束對話" tabindex="-1">Q: 什麼時候應該結束對話？ <a class="header-anchor" href="#q-什麼時候應該結束對話" aria-label="Permalink to &quot;Q: 什麼時候應該結束對話？&quot;">​</a></h3><p><strong>A:</strong> 以下幾種情況建議結束：</p><ol><li>您已完成預定的練習目標</li><li>AI 客戶表達想要結束對話（系統會彈出通知）</li><li>您覺得已達到學習效果</li><li>您想查看目前的評量結果</li></ol><hr><h2 id="評量報告" tabindex="-1">評量報告 <a class="header-anchor" href="#評量報告" aria-label="Permalink to &quot;評量報告&quot;">​</a></h2><h3 id="q-評量報告一直在「產生中」" tabindex="-1">Q: 評量報告一直在「產生中」？ <a class="header-anchor" href="#q-評量報告一直在「產生中」" aria-label="Permalink to &quot;Q: 評量報告一直在「產生中」？&quot;">​</a></h3><p><strong>A:</strong> 報告產生通常需要 30 秒至 2 分鐘。如果超過 5 分鐘仍未完成：</p><ol><li>嘗試重新整理頁面</li><li>等待片刻後再次查看</li><li>如問題持續，聯繫管理員</li></ol><p>報告的各區塊（階段評量、綜合評核等）是獨立產生的，可能有些區塊先完成。</p><h3 id="q-「綜合評核」和「逐句評價」有什麼不同" tabindex="-1">Q: 「綜合評核」和「逐句評價」有什麼不同？ <a class="header-anchor" href="#q-「綜合評核」和「逐句評價」有什麼不同" aria-label="Permalink to &quot;Q: 「綜合評核」和「逐句評價」有什麼不同？&quot;">​</a></h3><p><strong>A:</strong></p><table tabindex="0"><thead><tr><th>模式</th><th>說明</th></tr></thead><tbody><tr><td>綜合評核</td><td>整體性的分析，包含階段達成狀況、綜合表現評估、改善建議等</td></tr><tr><td>逐句評價</td><td>針對每一輪對話（您的訊息 + AI 回覆）進行逐條分析，提供具體的表達技巧回饋</td></tr></tbody></table><p>建議先看「綜合評核」了解整體表現，再切換「逐句評價」找出具體可改善的對話細節。</p><h3 id="q-「ai-內心思考」是什麼" tabindex="-1">Q: 「AI 內心思考」是什麼？ <a class="header-anchor" href="#q-「ai-內心思考」是什麼" aria-label="Permalink to &quot;Q: 「AI 內心思考」是什麼？&quot;">​</a></h3><p><strong>A:</strong> AI 內心思考顯示的是 AI 模擬客戶在收到您的訊息後的心理活動。這有助於您了解客戶在每個時刻的真實想法，幫助您下次調整溝通策略。</p><h3 id="q-我對評量結果不滿意-可以回饋嗎" tabindex="-1">Q: 我對評量結果不滿意，可以回饋嗎？ <a class="header-anchor" href="#q-我對評量結果不滿意-可以回饋嗎" aria-label="Permalink to &quot;Q: 我對評量結果不滿意，可以回饋嗎？&quot;">​</a></h3><p><strong>A:</strong> 可以。每個評量區塊下方都有評分功能：</p><ul><li><strong>正面</strong> — 覺得評核有幫助（可附加留言）</li><li><strong>中立</strong> — 預設，無特別意見</li><li><strong>負面</strong> — 覺得評核需要改善（需說明原因）</li></ul><p>您的回饋會幫助系統持續優化評量品質。</p><h3 id="q-為什麼顯示「未達成任何評核階段」" tabindex="-1">Q: 為什麼顯示「未達成任何評核階段」？ <a class="header-anchor" href="#q-為什麼顯示「未達成任何評核階段」" aria-label="Permalink to &quot;Q: 為什麼顯示「未達成任何評核階段」？&quot;">​</a></h3><p><strong>A:</strong> 這表示在本次練習中，AI 判斷您的對話未達到第一個銷售階段的標準。可能的原因：</p><ul><li>對話輪數太少</li><li>未展現足夠的破冰/建立信任行為</li><li>對話偏離銷售主題</li></ul><p>建議檢視逐句評價中的具體回饋，了解改善方向。</p><hr><h2 id="練習歷史" tabindex="-1">練習歷史 <a class="header-anchor" href="#練習歷史" aria-label="Permalink to &quot;練習歷史&quot;">​</a></h2><h3 id="q-篩選後找不到紀錄" tabindex="-1">Q: 篩選後找不到紀錄？ <a class="header-anchor" href="#q-篩選後找不到紀錄" aria-label="Permalink to &quot;Q: 篩選後找不到紀錄？&quot;">​</a></h3><p><strong>A:</strong> 請注意以下幾點：</p><ol><li>確認日期範圍設定正確</li><li>嘗試減少篩選條件範圍</li><li>點擊「清除全部」移除所有篩選，確認是否有紀錄存在</li><li>確認篩選標籤列中的條件是否符合預期</li></ol><p>如果確認沒有紀錄，表示在該條件下確實沒有進行過練習。</p><h3 id="q-「繼續練習」按鈕為什麼不能點" tabindex="-1">Q: 「繼續練習」按鈕為什麼不能點？ <a class="header-anchor" href="#q-「繼續練習」按鈕為什麼不能點" aria-label="Permalink to &quot;Q: 「繼續練習」按鈕為什麼不能點？&quot;">​</a></h3><p><strong>A:</strong> 只有狀態為「進行中」的練習才能繼續。如果練習已經被結束（手動結束或系統自動結束），就只能使用「重新挑戰」來開始新的對話。</p><hr><h2 id="知識助手" tabindex="-1">知識助手 <a class="header-anchor" href="#知識助手" aria-label="Permalink to &quot;知識助手&quot;">​</a></h2><h3 id="q-知識助手的回答不正確或不完整" tabindex="-1">Q: 知識助手的回答不正確或不完整？ <a class="header-anchor" href="#q-知識助手的回答不正確或不完整" aria-label="Permalink to &quot;Q: 知識助手的回答不正確或不完整？&quot;">​</a></h3><p><strong>A:</strong> 知識助手的回答品質取決於以下因素：</p><ol><li><strong>知識庫內容</strong> — 回答基於管理員上傳的文件。如果知識庫中沒有相關資料，回答可能不夠精準</li><li><strong>問題表述</strong> — 嘗試用不同的方式描述問題，可能獲得更好的結果</li><li><strong>內容時效性</strong> — 如果資料已過期，請聯繫管理員更新知識庫</li></ol><blockquote><p>知識助手的回答僅供參考，實際操作時請以公司正式文件為準。</p></blockquote><h3 id="q-看不到知識助手圖示" tabindex="-1">Q: 看不到知識助手圖示？ <a class="header-anchor" href="#q-看不到知識助手圖示" aria-label="Permalink to &quot;Q: 看不到知識助手圖示？&quot;">​</a></h3><p><strong>A:</strong> 您的帳號可能沒有知識庫閱讀權限。請聯繫管理員確認權限設定。</p><h3 id="q-對話紀錄消失了" tabindex="-1">Q: 對話紀錄消失了？ <a class="header-anchor" href="#q-對話紀錄消失了" aria-label="Permalink to &quot;Q: 對話紀錄消失了？&quot;">​</a></h3><p><strong>A:</strong> 知識助手的對話紀錄儲存在本地瀏覽器中。以下操作會導致紀錄消失：</p><ul><li>清除瀏覽器資料/快取</li><li>點擊「Clear Chat」按鈕</li><li>使用隱私瀏覽模式</li><li>更換瀏覽器或裝置</li></ul><hr><h2 id="管理員功能" tabindex="-1">管理員功能 <a class="header-anchor" href="#管理員功能" aria-label="Permalink to &quot;管理員功能&quot;">​</a></h2><h3 id="q-批次匯入使用者失敗" tabindex="-1">Q: 批次匯入使用者失敗？ <a class="header-anchor" href="#q-批次匯入使用者失敗" aria-label="Permalink to &quot;Q: 批次匯入使用者失敗？&quot;">​</a></h3><p><strong>A:</strong> 常見原因：</p><table tabindex="0"><thead><tr><th>原因</th><th>解決方式</th></tr></thead><tbody><tr><td>檔案不是 CSV 格式</td><td>確認儲存為 .csv 格式</td></tr><tr><td>CSV 欄位順序錯誤</td><td>下載範本，依範本格式填寫</td></tr><tr><td>Email 重複</td><td>確認沒有重複的 Email</td></tr><tr><td>缺少必填欄位</td><td>確認每列資料都完整</td></tr><tr><td>公司/部門代碼不存在</td><td>確認使用正確的公司與部門代碼</td></tr></tbody></table><p>系統會提供詳細的錯誤報告，包含每筆失敗資料的行號與具體原因。</p><h3 id="q-修改-prompt-後何時生效" tabindex="-1">Q: 修改 Prompt 後何時生效？ <a class="header-anchor" href="#q-修改-prompt-後何時生效" aria-label="Permalink to &quot;Q: 修改 Prompt 後何時生效？&quot;">​</a></h3><p><strong>A:</strong> 修改 Prompt 後，需要「發布」（啟用）該版本才會生效。生效後：</p><ul><li><strong>新的對話</strong> — 立即使用新版 Prompt</li><li><strong>已進行中的對話</strong> — 不受影響，繼續使用原版本</li></ul><h3 id="q-刪除階段會影響已完成的練習嗎" tabindex="-1">Q: 刪除階段會影響已完成的練習嗎？ <a class="header-anchor" href="#q-刪除階段會影響已完成的練習嗎" aria-label="Permalink to &quot;Q: 刪除階段會影響已完成的練習嗎？&quot;">​</a></h3><p><strong>A:</strong> 刪除階段不會影響已完成練習的資料，但可能影響該階段在評量報告中的顯示。建議在刪除前確認沒有進行中的練習使用該階段。</p><h3 id="q-如何恢復已刪除的使用者" tabindex="-1">Q: 如何恢復已刪除的使用者？ <a class="header-anchor" href="#q-如何恢復已刪除的使用者" aria-label="Permalink to &quot;Q: 如何恢復已刪除的使用者？&quot;">​</a></h3><p><strong>A:</strong> 系統使用軟刪除機制。已刪除的使用者資料仍保留在資料庫中。如需恢復，請聯繫系統管理員或技術團隊處理。</p><hr><h2 id="系統與效能" tabindex="-1">系統與效能 <a class="header-anchor" href="#系統與效能" aria-label="Permalink to &quot;系統與效能&quot;">​</a></h2><h3 id="q-系統載入很慢" tabindex="-1">Q: 系統載入很慢？ <a class="header-anchor" href="#q-系統載入很慢" aria-label="Permalink to &quot;Q: 系統載入很慢？&quot;">​</a></h3><p><strong>A:</strong> 建議檢查以下項目：</p><ol><li>網路連線速度是否穩定</li><li>是否使用支援的瀏覽器最新版本</li><li>嘗試關閉其他佔用資源的分頁</li><li>清除瀏覽器快取後重試</li></ol><h3 id="q-顯示「伺服器發生錯誤-請稍後再試」" tabindex="-1">Q: 顯示「伺服器發生錯誤，請稍後再試」？ <a class="header-anchor" href="#q-顯示「伺服器發生錯誤-請稍後再試」" aria-label="Permalink to &quot;Q: 顯示「伺服器發生錯誤，請稍後再試」？&quot;">​</a></h3><p><strong>A:</strong> 這表示後端服務暫時出現異常。建議：</p><ol><li>等待數分鐘後重試</li><li>如問題持續超過 30 分鐘，聯繫管理員或 IT 部門</li><li>請勿反覆重試，以免增加伺服器負擔</li></ol><h3 id="q-系統支援哪些瀏覽器" tabindex="-1">Q: 系統支援哪些瀏覽器？ <a class="header-anchor" href="#q-系統支援哪些瀏覽器" aria-label="Permalink to &quot;Q: 系統支援哪些瀏覽器？&quot;">​</a></h3><p><strong>A:</strong></p><table tabindex="0"><thead><tr><th>瀏覽器</th><th>支援版本</th></tr></thead><tbody><tr><td>Google Chrome</td><td>最新版本</td></tr><tr><td>Microsoft Edge</td><td>最新版本</td></tr><tr><td>Mozilla Firefox</td><td>最新版本</td></tr><tr><td>Apple Safari</td><td>最新版本</td></tr></tbody></table><p>建議使用 Chrome 或 Edge 以獲得最佳體驗。</p><hr><h2 id="錯誤訊息速查" tabindex="-1">錯誤訊息速查 <a class="header-anchor" href="#錯誤訊息速查" aria-label="Permalink to &quot;錯誤訊息速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>錯誤訊息</th><th>說明</th><th>處理方式</th></tr></thead><tbody><tr><td>認證失敗，請重新登入後再試</td><td>登入狀態已過期</td><td>重新登入</td></tr><tr><td>非預期的訪問，請稍後再試或聯繫管理人員</td><td>權限不足</td><td>確認帳號權限，聯繫管理員</td></tr><tr><td>請求過於頻繁，請稍後再試</td><td>操作頻率超過限制</td><td>等待數分鐘後再試</td></tr><tr><td>伺服器發生錯誤，請稍後再試</td><td>後端服務異常</td><td>等待後重試或聯繫 IT</td></tr><tr><td>網路連線錯誤</td><td>網路中斷</td><td>檢查網路連線</td></tr><tr><td>找不到資源</td><td>請求的資源不存在</td><td>確認操作目標是否正確</td></tr><tr><td>操作失敗</td><td>一般操作異常</td><td>重試或聯繫管理員</td></tr><tr><td>輸入資料不正確</td><td>表單驗證失敗</td><td>檢查輸入內容是否符合格式要求</td></tr><tr><td>包含不安全字符</td><td>XSS 防護觸發</td><td>移除特殊字元後重試</td></tr></tbody></table><hr><h2 id="還有問題" tabindex="-1">還有問題？ <a class="header-anchor" href="#還有問題" aria-label="Permalink to &quot;還有問題？&quot;">​</a></h2><p>如果以上 FAQ 無法解決您的問題：</p><ol><li>聯繫所屬公司的系統管理員</li><li>向 IT 部門提交服務請求</li><li>提供以下資訊以加速問題排解： <ul><li>您的帳號 Email</li><li>問題發生的時間</li><li>問題的詳細描述</li><li>螢幕截圖（如有）</li><li>錯誤訊息的完整內容</li></ul></li></ol>',119)])])}const u=a(i,[["render",e]]);export{p as __pageData,u as default};
